import java.util.*;

public class ServiceBoundaryAnalyzer {

    private final Map<String, List<String>> serviceCapabilities = new LinkedHashMap<>();

    public void addCapability(String serviceName, String capability) {
        serviceCapabilities
            .computeIfAbsent(serviceName, k -> new ArrayList<>())
            .add(capability);
    }

    public int serviceCount() {
        return serviceCapabilities.size();
    }

    public List<String> capabilitiesOf(String serviceName) {
        // Return capabilities for the given service, or empty list if not found
        return new ArrayList<>();
    }

    public boolean violatesSingleResponsibility(String serviceName, int maxCapabilities) {
        // Returns true if the service has more capabilities than the allowed max
        return false;
    }

    public static void main(String[] args) {
        ServiceBoundaryAnalyzer analyzer = new ServiceBoundaryAnalyzer();
        analyzer.addCapability("UserService", "register");
        analyzer.addCapability("UserService", "login");
        analyzer.addCapability("UserService", "updateProfile");
        analyzer.addCapability("OrderService", "placeOrder");
        analyzer.addCapability("OrderService", "cancelOrder");

        System.out.println("Services: " + analyzer.serviceCount());
        System.out.println("UserService capabilities: " + analyzer.capabilitiesOf("UserService"));
        System.out.println("Violates SRP (max 2): " + analyzer.violatesSingleResponsibility("UserService", 2));
    }
}

import java.util.*;

public class ServiceRegistry {

    public record ServiceInstance(String host, int port, boolean healthy) {}

    private final Map<String, List<ServiceInstance>> registry = new HashMap<>();

    public void register(String serviceName, String host, int port) {
        // Register a new healthy instance for the service
        registry.computeIfAbsent(serviceName, k -> new ArrayList<>())
                .add(new ServiceInstance(host, port, true));
    }

    public boolean deregister(String serviceName, String host, int port) {
        // Remove the instance matching host+port from the registry
        // Return true if removed, false if not found
        return false;
    }

    public List<ServiceInstance> discover(String serviceName) {
        // Return all healthy instances of the service
        return new ArrayList<>();
    }

    public static void main(String[] args) {
        ServiceRegistry registry = new ServiceRegistry();
        registry.register("payment-service", "10.0.0.1", 8080);
        registry.register("payment-service", "10.0.0.2", 8080);
        registry.register("inventory-service", "10.0.0.3", 9090);

        System.out.println("Payment instances: " + registry.discover("payment-service").size());
        boolean removed = registry.deregister("payment-service", "10.0.0.1", 8080);
        System.out.println("Removed: " + removed);
        System.out.println("Payment instances after: " + registry.discover("payment-service").size());
    }
}

